def error_response(message: str, status: int = 400, code: str = "bad_request"):
    return jsonify({"error": code, "message": message}), status


def require_auth():
    if not API_TOKEN:
        return None
    auth = request.headers.get("Authorization", "").strip()
    if auth == f"Bearer {API_TOKEN}":
        return None
    token = request.args.get("token", "")
    if token == API_TOKEN:
        return None
    return error_response("Unauthorized", 401, "unauthorized")


def normalize_url(raw_url: str) -> str:
    if not raw_url:
        raise ValueError("URL is required")
    raw_url = raw_url.strip()
    if len(raw_url) > MAX_URL_LENGTH:
        raise ValueError("URL too long")
    parsed = urllib.parse.urlparse(raw_url)
    if not parsed.scheme:
        raw_url = "https://" + raw_url
        parsed = urllib.parse.urlparse(raw_url)
    if parsed.scheme.lower() not in ALLOWED_SCHEMES:
        raise ValueError("Only http and https URLs are allowed")
    if not parsed.netloc:
        raise ValueError("Invalid URL")
    hostname = parsed.hostname
    if not hostname:
        raise ValueError("Invalid hostname")
    if is_private_or_local_host(hostname):
        raise ValueError("Local/private network URLs are not allowed")
    return parsed.geturl()


def is_private_or_local_host(hostname: str) -> bool:
    host = hostname.lower()
    if host in {"localhost"}:
        return True
    if host.endswith(".local") or host.endswith(".internal"):
        return True
    ipv4_match = re.match(r"^(\d{1,3}\.){3}\d{1,3}$", host)
    if ipv4_match:
        parts = [int(x) for x in host.split(".")]
        if parts[0] == 10:
            return True
        if parts[0] == 127:
            return True
        if parts[0] == 169 and parts[1] == 254:
            return True
        if parts[0] == 172 and 16 <= parts[1] <= 31:
            return True
        if parts[0] == 192 and parts[1] == 168:
            return True
        if parts[0] == 0:
            return True
    if ":" in host:
        if host == "::1":
            return True
        if host.startswith("fc") or host.startswith("fd") or host.startswith("fe80"):
            return True
    return False


def validate_dimensions(width: int, height: int) -> Tuple[int, int]:
    if width <= 0 or height <= 0:
        raise ValueError("Width and height must be positive")
    if width > MAX_DIMENSION or height > MAX_DIMENSION:
        raise ValueError(f"Width and height must be <= {MAX_DIMENSION}")
    return width, height


def make_object_key(url: str, thumb_w: int, thumb_h: int) -> str:
    ts = datetime.now(timezone.utc).strftime("%Y/%m/%d")
    digest = hashlib.sha256(f"{url}|{thumb_w}|{thumb_h}".encode("utf-8")).hexdigest()
    return f"{S3_PREFIX}/{ts}/{digest}.jpg"


def file_exists_in_s3(bucket: str, key: str) -> bool:
    try:
        s3.head_object(Bucket=bucket, Key=key)
        return True
    except ClientError as e:
        code = e.response.get("Error", {}).get("Code")
        if code in ("404", "NoSuchKey", "NotFound"):
            return False
        raise


def generate_presigned_url(bucket: str, key: str) -> str:
    return s3.generate_presigned_url(
        "get_object",
        Params={"Bucket": bucket, "Key": key},
        ExpiresIn=SIGNED_URL_EXPIRES,
    )


def upload_bytes_to_s3(data: bytes, bucket: str, key: str, content_type: str = "image/jpeg"):
    s3.put_object(
        Bucket=bucket,
        Key=key,
        Body=data,
        ContentType=content_type,
        CacheControl="public, max-age=31536000, immutable",
        ACL="private",
        Metadata={"service": APP_NAME},
    )


def run_chrome_screenshot(url: str, output_png: str, width: int, height: int):
    cmd = [
        CHROME_BIN,
        "--headless=new",
        "--disable-gpu",
        "--no-sandbox",
        "--hide-scrollbars",
        f"--window-size={width},{height}",
        f"--user-agent={USER_AGENT}",
        f"--screenshot={output_png}",
        url,
    ]
    logger.info("Running Chrome screenshot command")
    result = subprocess.run(
        cmd,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        timeout=max(10, PAGE_LOAD_TIMEOUT_MS // 1000 + 15),
        check=False,
        text=True,
    )
    if result.returncode != 0:
        raise RuntimeError(f"Chrome screenshot failed: {result.stderr.strip() or result.stdout.strip()}")


def run_phantomjs_screenshot(url: str, output_png: str, width: int, height: int):
    script = f"""
var page = require('webpage').create();
page.settings.userAgent = {json.dumps(USER_AGENT)};
page.viewportSize = {{ width: {width}, height: {height} }};
page.open({json.dumps(url)}, function(status) {{
  if (status !== 'success') {{
    console.log('LOAD_FAILED');
    phantom.exit(1);
  }}
  window.setTimeout(function() {{
    page.render({json.dumps(output_png)});
    phantom.exit(0);
  }}, {CAPTURE_DELAY_MS});
}});
"""
    with tempfile.NamedTemporaryFile(mode="w", suffix=".js", delete=False) as f:
        script_path = f.name
        f.write(script)
    try:
        result = subprocess.run(
            [PHANTOMJS_BIN, script_path],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            timeout=max(10, PAGE_LOAD_TIMEOUT_MS // 1000 + 15),
            check=False,
            text=True,
        )
        if result.returncode != 0:
            raise RuntimeError(f"PhantomJS screenshot failed: {result.stderr.strip() or result.stdout.strip()}")
    finally:
        try:
            os.remove(script_path)
        except OSError:
            pass


def capture_screenshot(url: str, width: int, height: int) -> bytes:
    with tempfile.TemporaryDirectory() as tmpdir:
        png_path = os.path.join(tmpdir, f"{uuid.uuid4().hex}.png")
        if USE_PHANTOMJS:
            run_phantomjs_screenshot(url, png_path, width, height)
        else:
            run_chrome_screenshot(url, png_path, width, height)
        with open(png_path, "rb") as f:
            return f.read()


def make_thumbnail(image_bytes: bytes, thumb_w: int, thumb_h: int, quality: int = 85) -> bytes:
    with Image.open(io.BytesIO(image_bytes)) as img:
        img = img.convert("RGB")
        img.thumbnail((thumb_w, thumb_h))
        out = io.BytesIO()
        img.save(out, format="JPEG", quality=quality, optimize=True)
        return out.getvalue()


