@app.route("/screenshot", methods=["POST"])
def screenshot():
    auth_err = require_auth()
    if auth_err:
        return auth_err

    if not S3_BUCKET:
        return error_response("S3_BUCKET is not configured", 500, "server_error")

    payload = request.get_json(silent=True) or {}
    raw_url = payload.get("url") or request.form.get("url") or request.args.get("url")
    if not raw_url:
        return error_response("Missing url")

    try:
        url = normalize_url(raw_url)
        viewport_w = int(payload.get("viewport_width", request.args.get("viewport_width", DEFAULT_VIEWPORT_WIDTH)))
        viewport_h = int(payload.get("viewport_height", request.args.get("viewport_height", DEFAULT_VIEWPORT_HEIGHT)))
        thumb_w = int(payload.get("thumb_width", request.args.get("thumb_width", DEFAULT_THUMB_WIDTH)))
        thumb_h = int(payload.get("thumb_height", request.args.get("thumb_height", DEFAULT_THUMB_HEIGHT)))
        validate_dimensions(viewport_w, viewport_h)
        validate_dimensions(thumb_w, thumb_h)
    except ValueError as e:
        return error_response(str(e), 400, "validation_error")

    key = make_object_key(url, thumb_w, thumb_h)

    try:
        if file_exists_in_s3(S3_BUCKET, key):
            signed_url = generate_presigned_url(S3_BUCKET, key)
            return jsonify(
                {
                    "url": url,
                    "bucket": S3_BUCKET,
                    "key": key,
                    "image_url": signed_url,
                    "cached": True,
                }
            )

        screenshot_png = capture_screenshot(url, viewport_w, viewport_h)
        thumb_jpg = make_thumbnail(screenshot_png, thumb_w, thumb_h)
        upload_bytes_to_s3(thumb_jpg, S3_BUCKET, key, "image/jpeg")
        signed_url = generate_presigned_url(S3_BUCKET, key)

        return jsonify(
            {
                "url": url,
                "bucket": S3_BUCKET,
                "key": key,
                "image_url": signed_url,
                "cached": False,
            }
        )
    except subprocess.TimeoutExpired:
        logger.exception("Screenshot timeout")
        return error_response("Screenshot timed out", 504, "timeout")
    except Exception as e:
        logger.exception("Failed to process screenshot")
        return error_response(str(e), 500, "server_error")


@app.route("/thumbnail", methods=["GET"])
def thumbnail_proxy():
    auth_err = require_auth()
    if auth_err:
        return auth_err

    if not S3_BUCKET:
        return error_response("S3_BUCKET is not configured", 500, "server_error")

    raw_url = request.args.get("url", "")
    if not raw_url:
        return error_response("Missing url")

    try:
        url = normalize_url(raw_url)
        viewport_w = int(request.args.get("viewport_width", DEFAULT_VIEWPORT_WIDTH))
        viewport_h = int(request.args.get("viewport_height", DEFAULT_VIEWPORT_HEIGHT))
        thumb_w = int(request.args.get("thumb_width", DEFAULT_THUMB_WIDTH))
        thumb_h = int(request.args.get("thumb_height", DEFAULT_THUMB_HEIGHT))
        validate_dimensions(viewport_w, viewport_h)
        validate_dimensions(thumb_w, thumb_h)
        key = make_object_key(url, thumb_w, thumb_h)

        if not file_exists_in_s3(S3_BUCKET, key):
            screenshot_png = capture_screenshot(url, viewport_w, viewport_h)
            thumb_jpg = make_thumbnail(screenshot_png, thumb_w, thumb_h)
            upload_bytes_to_s3(thumb_jpg, S3_BUCKET, key, "image/jpeg")

        obj = s3.get_object(Bucket=S3_BUCKET, Key=key)
        data = obj["Body"].read()
        return send_file(io.BytesIO(data), mimetype="image/jpeg", download_name="thumbnail.jpg")
    except subprocess.TimeoutExpired:
        logger.exception("Thumbnail timeout")
        return error_response("Screenshot timed out", 504, "timeout")
    except Exception as e:
        logger.exception("Failed to serve thumbnail")
        return error_response(str(e), 500, "server_error")


